-- LESSON 19: THE SUBJUNCTIVE MOOD
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  73, 19, 'grammar', 'The Subjunctive Mood', 'Possibility, purpose & condition — Advanced',
  '{"concept":"The Subjunctive Mood","symbol":"λύω → λύῃ","difficulty":"Advanced","overview":"The Indicative mood states facts; the Subjunctive mood expresses possibility, probability, contingency, or the speaker''s attitude. The Subjunctive is the mood of maybe, might, should, in order that. It uses lengthened thematic vowels (ο → ω; ε → η) and appears in purpose clauses (ἵνα + subjunctive), conditional sentences (ἐάν + subjunctive), prohibitions (μή + aorist subjunctive), and indefinite relative/temporal clauses (ἂν + relative + subjunctive).","key_points":["Subjunctive = the mood of possibility, purpose, contingency","Distinguished from indicative by lengthened vowels: -ω, -ῃς, -ῃ, -ωμεν, -ητε, -ωσι","Purpose clause: ἵνα + subjunctive (in order that)","Condition: ἐάν + subjunctive (if — third class condition, real probability)","Prohibition: μή + aorist subjunctive (don''t even start doing this)","Indefinite: ὅς ἐάν / ὅταν + subjunctive (whoever, whenever)","Hortatory subjunctive: 1st plural — let us love (ἀγαπῶμεν)"],"examples":[{"greek":"ἵνα πᾶς ὁ πιστεύων εἰς αὐτὸν ἔχῃ ζωὴν αἰώνιον","translation":"in order that everyone believing in him might have eternal life","reference":"John 3:15","note":"ἵνα + subjunctive (ἔχῃ) — purpose clause. The purpose of the cross: that those who believe might have (subjunctive, ongoing) eternal life"},{"greek":"ἐάν τις ἁμάρτῃ","translation":"if anyone should sin","reference":"1 John 2:1","note":"ἐάν + aorist subjunctive (ἁμάρτῃ) — third class condition: a real possibility. John writes for the case that any believer sins"},{"greek":"ἀγαπῶμεν ἀλλήλους","translation":"let us love one another","reference":"1 John 4:7","note":"1st plural present subjunctive — hortatory subjunctive. A warm exhortation: let us keep on loving one another"}],"tables":[{"title":"Present Active Subjunctive: λύω","headers":["Person","Singular","Plural"],"rows":[["1st","λύω (I may loose)","λύωμεν (let us loose)"],["2nd","λύῃς (you may loose)","λύητε (you all may loose)"],["3rd","λύῃ (he may loose)","λύωσι(ν) (they may loose)"]]},{"title":"Key Subjunctive Constructions","headers":["Construction","Form","Meaning","Example"],"rows":[["Purpose","ἵνα + subj","in order that","ἵνα ἔχητε ζωήν"],["Condition","ἐάν + subj","if (probable)","ἐάν τις ἁμάρτῃ"],["Prohibition","μή + aor subj","don''t! (stop/never start)","μή κλέψῃς"],["Indefinite","ὅς ἂν + subj","whoever","ὅς ἂν πίῃ"],["Hortatory","1st pl subj","let us...","ἀγαπῶμεν"],["Deliberative","question + subj","what should we do?","τί ποιῶμεν;"]]}],"practice":[{"type":"identify","question":"What is the key grammatical signal that distinguishes the Subjunctive from the Indicative in Greek?","answer":"Lengthened thematic vowels — ο becomes ω, ε becomes η (e.g. λύει indicative vs λύῃ subjunctive)"},{"type":"choice","question":"ἵνα + subjunctive expresses purpose. In John 3:16 the purpose clause is ἵνα...ἔχῃ ζωὴν αἰώνιον. What is the purpose of God giving His Son?","options":["To judge the world","That everyone believing might have eternal life","To fulfil the law only","To establish the church"],"answer":1},{"type":"choice","question":"ἐάν + subjunctive is a third class condition. What does this indicate about the condition?","options":["It is impossible","It is a real, genuinely possible future contingency","It is certainly going to happen","It happened in the past"],"answer":1}]}',
  '[{"ref":"John 3:16","text":"that whosoever believeth in him should not perish, but have everlasting life","note":"ἵνα μὴ ἀπόληται ἀλλ'' ἔχῃ ζωὴν αἰώνιον — two subjunctives: ἀπόληται (perish, aorist subj, prevented by μή) and ἔχῃ (have, present subj, ongoing possession). The grammar of salvation in one purpose clause"},{"ref":"1 John 2:1","text":"My little children, these things write I unto you, that ye sin not. And if any man sin, we have an advocate with the Father, Jesus Christ the righteous","note":"ἐάν τις ἁμάρτῃ (ἐάν + aorist subjunctive) — the compassionate third class condition. John''s pastoral realism: he doesn''t pretend believers never sin. The subjunctive acknowledges the real possibility and immediately offers the remedy: an Advocate"}]'
);

-- LESSON 20: THE IMPERATIVE MOOD
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  74, 20, 'grammar', 'The Imperative Mood', 'Commands & prohibitions — Advanced',
  '{"concept":"The Imperative Mood","symbol":"λῦε! — Loose!","difficulty":"Advanced","overview":"The Imperative mood expresses commands, exhortations, requests, and prohibitions. Greek has imperatives in 2nd and 3rd person (English only uses 2nd person commands). Tense is crucial in imperatives: Present imperative = keep on doing (ongoing command); Aorist imperative = do it now, decisively (summary command). The distinction between present and aorist imperatives carries significant pastoral weight in the NT letters.","key_points":["Present imperative: ongoing, repeated, habitual command — keep doing this","Aorist imperative: decisive, summary command — do this now","Prohibition with μή + present imperative: stop doing this (you were already doing it)","Prohibition with μή + aorist subjunctive: don''t even start (you weren''t yet doing it)","3rd person imperative: let him..., let them... — used for indirect commands","The Great Commission (Matt 28:19) uses the aorist imperative for the main command","Pray without ceasing (1 Thess 5:17) is a present imperative — keep on praying"],"examples":[{"greek":"Μετανοεῖτε (present imperative)","translation":"Keep repenting! Repent continuously!","reference":"Matthew 4:17","note":"Present imperative — repentance is not a one-time act but an ongoing lifestyle and posture before God"},{"greek":"μαθητεύσατε (aorist imperative)","translation":"Make disciples! (the decisive command)","reference":"Matthew 28:19","note":"Aorist imperative — the decisive, summary command. This is the one imperative in the Great Commission"},{"greek":"μὴ στρεφόμενος (present imperative + μή)","translation":"Stop turning back / Do not keep turning","reference":"Luke 9:62","note":"μή + present imperative = stop doing what you''re already doing. The implication: someone was already looking back"}],"tables":[{"title":"Present Active Imperative: λύω","headers":["Person","Singular","Plural"],"rows":[["2nd","λῦε (keep loosing!)","λύετε (keep loosing, all of you!)"],["3rd","λυέτω (let him keep loosing)","λυέτωσαν (let them keep loosing)"]]},{"title":"Aorist Active Imperative: λύσω","headers":["Person","Singular","Plural"],"rows":[["2nd","λῦσον (loose it now!)","λύσατε (loose it now, all of you!)"],["3rd","λυσάτω (let him loose it)","λυσάτωσαν (let them loose it)"]]},{"title":"Prohibitions","headers":["Form","Meaning","Implication"],"rows":[["μή + present imperative","Stop doing X","You were already doing it; cease"],["μή + aorist subjunctive","Don''t ever do X","You haven''t started; don''t begin"]]}],"practice":[{"type":"identify","question":"What is the difference between a Present Imperative and an Aorist Imperative in terms of the kind of action commanded?","answer":"Present imperative = keep doing (ongoing habit); Aorist imperative = do it now decisively (summary command)"},{"type":"choice","question":"1 Thessalonians 5:17 says Pray without ceasing (προσεύχεσθε ἀδιαλείπτως — present imperative). What does the present imperative communicate?","options":["Pray one time decisively","Keep on praying — make it a continuous, unceasing habit","Start praying (you haven''t started)","Pray loudly"],"answer":1},{"type":"choice","question":"μή + present imperative means stop doing something. What does μή + aorist subjunctive mean?","options":["Stop what you started","Don''t ever begin this at all","Slow down","Do this occasionally"],"answer":1}]}',
  '[{"ref":"Matthew 28:19","text":"Go ye therefore, and teach all nations, baptizing them in the name of the Father, and of the Son, and of the Holy Ghost","note":"μαθητεύσατε — aorist imperative (decisive command: make disciples now and fully). The participles (going, baptizing, teaching) are ongoing present participles — the method is continuous; the mission is decisive"},{"ref":"1 Thessalonians 5:16–18","text":"Rejoice evermore. Pray without ceasing. In every thing give thanks","note":"Three commands: χαίρετε (rejoice, present), προσεύχεσθε (pray, present), εὐχαριστεῖτε (give thanks, present) — all present imperatives. Paul''s trinitarian formula for the Christian life: ongoing joy, ongoing prayer, ongoing gratitude"}]'
);

-- LESSON 21: PARTICIPLES (ADVANCED)
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  75, 21, 'grammar', 'Participles — Advanced', 'Attributive, circumstantial & genitive absolute — Advanced',
  '{"concept":"Advanced Participle Uses","symbol":"λύων · λύσας · λελυκώς","difficulty":"Advanced","overview":"Beyond the basic introduction (Lesson 15), Greek participles have several advanced uses that are essential for NT exegesis. The three main uses are: (1) Attributive — modifies a noun like an adjective; (2) Substantival — functions as a noun itself; (3) Circumstantial — describes the circumstances of the main verb (when, while, because, although, if, by). Tense in circumstantial participles encodes timing and logical relationship to the main verb.","key_points":["Attributive: ὁ πιστεύων (the believing one) — with article, modifies noun","Circumstantial: action or state accompanying the main verb — time, cause, means, concession","Aorist circumstantial participle: action prior to main verb — having believed, he...","Present circumstantial participle: action simultaneous with main verb — while believing, he...","Genitive absolute: participle + subject in genitive case, grammatically independent of main clause","Redundant participle (pleonastic): ἀποκριθεὶς εἶπεν (answering, he said) — common Semitic idiom in NT"],"examples":[{"greek":"εἰπὼν δὲ ταῦτα ἐπορεύθη εἰς Ἱεροσόλυμα","translation":"Having said these things he journeyed to Jerusalem","reference":"Luke 19:28","note":"Aorist participle εἰπών (having said) is prior to the main verb ἐπορεύθη (journeyed). The saying happened first, then the journey"},{"greek":"ἐλθόντος δὲ αὐτοῦ εἰς Καφαρναούμ","translation":"When he had come into Capernaum","reference":"Matthew 8:5","note":"Genitive absolute — αὐτοῦ ἐλθόντος (him having come, genitive + genitive participle). Subject of the participle (αὐτοῦ) is different from main verb subject"},{"greek":"ὁ νικῶν κληρονομήσει ταῦτα","translation":"The one who overcomes will inherit these things","reference":"Revelation 21:7","note":"Substantival present participle ὁ νικῶν = the overcomer (the one overcoming). Occurs 7 times in Revelation 2-3 as the defining description of the faithful Christian"}],"tables":[{"title":"Three Main Participle Uses","headers":["Use","Article?","Function","Example"],"rows":[["Attributive","Yes","Modifies noun like adjective","ὁ ἀγαθὸς λόγος — the good word"],["Substantival","Yes","Functions as noun itself","ὁ πιστεύων — the one believing"],["Circumstantial","No","Describes circumstances of main verb","πιστεύσας σωθήσεται — having believed he will be saved"]]},{"title":"Circumstantial Participle Time Relationships","headers":["Tense","Timing","Translation","Example"],"rows":[["Present participle","Same time as main verb","while/as (he does X, he does Y)","λέγων ἀπῆλθεν — saying this, he left"],["Aorist participle","Prior to main verb","after/having done (X, he then did Y)","εἰπὼν ἀπῆλθεν — having said, he left"],["Perfect participle","State continuing from past","having (already) done...","πεπιστευκὼς ζήσεται — having believed, he will live"]]}],"practice":[{"type":"identify","question":"What is the genitive absolute construction in Greek?","answer":"A participle and its subject, both in the genitive case, forming a clause grammatically independent from the main clause"},{"type":"choice","question":"ὁ νικῶν (present participle) in Revelation 2-3 functions as a substantival participle. What does it mean?","options":["The victory","The one who has already won","The one who keeps on overcoming / the overcomer","Overcome!"],"answer":2},{"type":"choice","question":"An AORIST circumstantial participle describes action that is ___ relative to the main verb.","options":["Simultaneous","Prior (happening before the main verb''s action)","Future","Continuous"],"answer":1}]}',
  '[{"ref":"Revelation 21:7","text":"He that overcometh shall inherit all things; and I will be his God, and he shall be my son","note":"ὁ νικῶν — the overcoming one. Seven times in Revelation 2-3 this substantival present participle defines the faithful Christian. The ongoing nature of the present tense shows victory is a lifestyle, not a one-time event"},{"ref":"Matthew 8:5","text":"And when Jesus was entered into Capernaum, there came unto him a centurion, beseeching him","note":"Εἰσελθόντι δὲ αὐτῷ — genitive absolute (him having entered). The centurion''s faith story begins with a genitive absolute construction that sets the scene. The grammar of Matthew signals narrative transitions with this advanced construction"}]'
);

-- LESSON 22: CONDITIONAL SENTENCES
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  76, 22, 'grammar', 'The Four Conditional Sentences', 'If...then — Four classes — Advanced',
  '{"concept":"The Four Greek Conditional Sentences","symbol":"εἰ · ἐάν","difficulty":"Advanced","overview":"Greek has four distinct conditional sentence types (classes), each encoding the speaker''s assumption about the truth or probability of the condition. The class affects the logical strength and nature of the if-then argument. Recognising which class a conditional belongs to is essential for NT exegesis — it tells you whether Paul assumes his condition is true, possible, unlikely, or contrary to fact.","key_points":["First Class: εἰ + indicative (any tense). Assumed true for argument''s sake. If, and for argument I''ll grant it (whether true or not).","Second Class: εἰ + past indicative + ἄν + past indicative. Contrary to fact. If it were so (but it''s not)","Third Class: ἐάν + subjunctive + indicative. Future probability. If (should) this happen (genuine open question)","Fourth Class: εἰ + optative (rare, incomplete in NT). Remote future possibility. If ever this might happen","The protasis is the if-clause; the apodosis is the then-clause","First class conditions do NOT guarantee the truth of the condition — they grant it for argument"],"examples":[{"greek":"εἰ υἱὸς εἶ τοῦ θεοῦ (1st class)","translation":"If you are the Son of God (and for argument''s sake I''m granting it)...","reference":"Matthew 4:3","note":"Satan uses a 1st class condition — he''s not conceding Jesus is the Son; he''s testing whether Jesus will use His power selfishly"},{"greek":"εἰ ἦν ὧδε οὐκ ἂν ἀπέθανεν (2nd class)","translation":"If you had been here (but you weren''t), my brother would not have died (but he did)","reference":"John 11:21","note":"2nd class contrary-to-fact: Martha knows Lazarus is dead. The grammar encodes her grief — the condition was NOT met in reality"},{"greek":"ἐάν τις ἀγαπᾷ με (3rd class)","translation":"If anyone loves me (open question, genuine possibility)","reference":"John 14:23","note":"3rd class condition: Jesus opens the promise to any and all who choose to love Him — the subjunctive keeps it genuinely open"}],"tables":[{"title":"The Four Conditional Classes","headers":["Class","Protasis","Apodosis","Speaker''s Assumption","Example"],"rows":[["1st (Simple)","εἰ + indicative","any form","Assumed true for argument","εἰ υἱὸς εἶ (Matt 4:3)"],["2nd (Contrary to fact)","εἰ + impf/aor indic","ἄν + impf/aor indic","Assumed FALSE","εἰ ἦν...οὐκ ἂν ἀπέθανεν"],["3rd (Future probable)","ἐάν + subjunctive","present/future indic","Open possibility","ἐάν τις ἀγαπᾷ με"],["4th (Future remote)","εἰ + optative","ἄν + optative","Very remote","Rare and incomplete in NT"]]}],"practice":[{"type":"identify","question":"What is the key difference between a 1st class and a 2nd class conditional sentence?","answer":"1st class: condition assumed as true for the argument (may or may not be actually true). 2nd class: condition assumed to be CONTRARY TO FACT — the condition was not met."},{"type":"choice","question":"John 11:21 — If you had been here, my brother would not have died (2nd class conditional). What does this tell us about Martha''s understanding of the situation?","options":["She thinks Jesus could still help","She is stating that the condition WAS NOT met — Lazarus is genuinely dead, and she knows it","She is uncertain whether Lazarus is dead","She is rebuking Jesus"],"answer":1},{"type":"choice","question":"ἐάν + subjunctive is a 3rd class condition. In John 3:16 (whosoever believeth), what does the open nature of ἐάν communicate?","options":["Only a few will believe","Belief is predetermined with no genuine choice","The offer is genuinely open to all — a real possibility for any person","Only Jews may believe"],"answer":2}]}',
  '[{"ref":"John 11:21","text":"Then said Martha unto Jesus, Lord, if thou hadst been here, my brother had not died","note":"εἰ ἦς ὧδε, οὐκ ἂν ἀπέθανεν — 2nd class contrary-to-fact condition. The grammar carries Martha''s grief: the condition was NOT met. Lazarus IS dead. Her faith and her loss collide in this conditional sentence"},{"ref":"Matthew 4:3","text":"And when the tempter came to him, he said, If thou be the Son of God, command that these stones be made bread","note":"εἰ υἱὸς εἶ — 1st class condition. Satan doesn''t deny Jesus is the Son; he tests whether Jesus will use His identity to satisfy self-interest. The 1st class grammar is Satan''s subtle acknowledgment while pressing the temptation"}]'
);

-- LESSON 23: INDIRECT DISCOURSE
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  77, 23, 'grammar', 'Indirect Discourse', 'Reporting what was said or thought — Advanced',
  '{"concept":"Indirect Discourse","symbol":"ὅτι · infinitive · participle","difficulty":"Advanced","overview":"Indirect discourse reports the content of someone''s speech or thought indirectly (He said that... rather than He said: ...). Greek has three main methods of indirect discourse: (1) ὅτι + indicative verb (most common — retains original tense of the direct statement); (2) Infinitive construction (with verbs of commanding, wishing, believing); (3) Participle construction (with verbs of perceiving, knowing). Understanding which method applies — and the tense retention rules — is crucial for NT exegesis.","key_points":["Method 1: ὅτι + indicative — tense of indirect clause = tense of original speech","Method 2: Infinitive — with verbs of commanding (κελεύω), wishing (βούλομαι), believing (πιστεύω)","Method 3: Participle — with verbs of knowing (οἶδα), seeing (ὁράω), finding (εὑρίσκω)","Tense retention: the original speaker''s tense is preserved in ὅτι clauses (historic present, aorist, etc.)","The ὅτι recitative introduces direct quotation (like English quotation marks): He said, that = He said:","Context determines whether ὅτι is because (causal) or that (content)"],"examples":[{"greek":"πιστεύω ὅτι σὺ εἶ ὁ Χριστός","translation":"I believe that you are the Christ","reference":"John 11:27","note":"πιστεύω + ὅτι + indicative — indirect discourse stating the content of Martha''s belief. The present tense εἶ is retained from her conviction"},{"greek":"λέγει αὐτοῖς ὁ Ἰησοῦς· Ἐγώ εἰμι","translation":"Jesus says to them: I am (he)","reference":"John 18:5","note":"Historical present (λέγει) + ὅτι recitative — here functioning as quotation marks for the direct speech that follows"},{"greek":"οἴδαμεν ὅτι ὁ νόμος πνευματικός ἐστιν","translation":"We know that the law is spiritual","reference":"Romans 7:14","note":"οἴδαμεν + ὅτι + present indicative — indirect discourse reporting shared theological conviction. The present tense is retained from the original reality"}],"tables":[{"title":"Three Methods of Indirect Discourse","headers":["Method","Introducing verb type","Construction","Example"],"rows":[["ὅτι clause","Saying, knowing, believing","ὅτι + indicative","λέγει ὅτι ζῇ (he says that he lives)"],["Infinitive","Commanding, wishing","subject + accusative + infinitive","κελεύει αὐτὸν ἐλθεῖν (he commands him to come)"],["Participle","Perceiving, knowing","accusative + participle","ὁρῶ αὐτὸν ἐρχόμενον (I see him coming)"]]},{"title":"Causal vs Content ὅτι","headers":["Meaning","Context","Example","Translation"],"rows":[["Content (that)","After verbs of saying/knowing/believing","πιστεύω ὅτι ζῇ","I believe that he lives"],["Causal (because)","Explaining a reason","χαίρω ὅτι ἀπέθανεν","I rejoice because he died"]]}],"practice":[{"type":"identify","question":"What is the most common method of indirect discourse in Greek NT?","answer":"ὅτι + indicative verb, retaining the original tense of the reported speech"},{"type":"choice","question":"John 11:27 — πιστεύω ὅτι σὺ εἶ ὁ Χριστός. This is indirect discourse. What belief is being reported?","options":["Martha''s doubt","Martha''s confession: I believe that You are the Christ — the content of her faith","Martha''s future hope only","Martha''s prayer"],"answer":1},{"type":"choice","question":"In Romans 7:14, οἴδαμεν ὅτι ὁ νόμος πνευματικός ἐστιν — what does the ὅτι introduce here?","options":["The cause of what was just said","The content of what we know — that the law is spiritual","A conditional statement","A relative clause"],"answer":1}]}',
  '[{"ref":"John 11:27","text":"She saith unto him, Yea, Lord: I believe that thou art the Christ, the Son of God, which should come into the world","note":"πεπίστευκα ὅτι σύ εἶ ὁ Χριστός (perfect + ὅτι + indicative) — I have believed and continue to believe (perfect) that you are (present, retained) the Christ. Martha''s indirect discourse confession equals Peter''s in theological weight"},{"ref":"Romans 7:14","text":"For we know that the law is spiritual: but I am carnal, sold under sin","note":"οἴδαμεν ὅτι — we know that (indirect discourse, common Pauline formula). Paul uses this construction repeatedly in Romans to signal shared theological premises before building his argument. Knowing the indirect discourse marker helps you follow Paul''s logic"}]'
);

-- LESSON 24: THE GENITIVE ABSOLUTE
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  78, 24, 'grammar', 'The Genitive Absolute', 'Independent participial clause — Advanced',
  '{"concept":"The Genitive Absolute","symbol":"αὐτοῦ εἰπόντος — him having spoken","difficulty":"Advanced","overview":"The genitive absolute is a grammatically independent participial clause in which both the participle and its subject stand in the genitive case, while having no grammatical connection to the main clause. The subject of the genitive absolute is DIFFERENT from the subject of the main verb — that is what makes it absolute (unattached). This construction is frequently used in NT narrative to set the scene for a main clause, functioning like a temporal, causal, or circumstantial clause.","key_points":["Genitive absolute = participiple in genitive + its subject in genitive, grammatically independent","Subject of genitive absolute is DIFFERENT from main clause subject","Most often temporal: when he had..., while they were...","Can be causal: because he had said..., or concessive: although they knew...","Extremely common in narrative sections of Gospels and Acts","Identified by: genitive noun/pronoun + genitive participle at the start of a sentence","The participle tense shows relationship to main verb: aorist = prior; present = simultaneous"],"examples":[{"greek":"αὐτοῦ δὲ πορευομένου ἐθαύμασαν οἱ ὄχλοι","translation":"While he was going, the crowds marvelled","reference":"Matthew 9:33","note":"αὐτοῦ πορευομένου — genitive absolute (him while going). Subject of genitive absolute = αὐτοῦ (him). Subject of main verb = οἱ ὄχλοι (the crowds). Different subjects — correctly an absolute"},{"greek":"ἐλθόντος δὲ αὐτοῦ εἰς Καφαρναούμ","translation":"When he had come into Capernaum","reference":"Matthew 8:5","note":"Aorist genitive absolute — αὐτοῦ ἐλθόντος (him having come). Used to introduce a new scene. Note: different from the disciples who are the implied background"},{"greek":"ταῦτα δὲ αὐτοῦ εἰπόντος πολλοὶ ἐπίστευσαν","translation":"And when he had said these things, many believed","reference":"John 8:30","note":"Aorist genitive absolute — αὐτοῦ εἰπόντος (him having spoken). The speaking is prior to and precipitates the believing. Classic narrative transition"}],"tables":[{"title":"Genitive Absolute Structure","headers":["Element","Grammatical form","Example"],"rows":[["Subject (different from main)","Genitive noun or pronoun","αὐτοῦ (him, genitive)"],["Participle","Genitive participle (agrees with subject)","εἰπόντος (having spoken, genitive)"],["Main clause","Independent clause, different subject","πολλοὶ ἐπίστευσαν (many believed)"]]},{"title":"Genitive Absolute Tense and Meaning","headers":["Participle Tense","Logical Relationship","Translation"],"rows":[["Aorist","Prior action","When/after he had...",""],["Present","Simultaneous action","While/as he was...",""],["Perfect","Prior state continuing","Having (already)...",""]]}],"practice":[{"type":"identify","question":"What makes a participial clause a genuine genitive absolute?","answer":"The subject of the participial clause is DIFFERENT from the subject of the main clause — both the subject and participle stand in the genitive case"},{"type":"choice","question":"In Matthew 8:5, ἐλθόντος δὲ αὐτοῦ (him having come) is a genitive absolute. What clues identify it?","options":["Both αὐτοῦ (pronoun) and ἐλθόντος (participle) are in the genitive case, and Jesus is different from the centurion who approaches","The verb ἐλθόντος is in the accusative case","The main verb is also in the genitive","αὐτοῦ is the subject of the main verb"],"answer":0},{"type":"choice","question":"An aorist genitive absolute participle indicates its action is ___ to the main verb.","options":["Simultaneous","Subsequent","Prior (completed before the main verb)","Unrelated"],"answer":2}]}',
  '[{"ref":"Matthew 8:5","text":"And when Jesus was entered into Capernaum, there came unto him a centurion, beseeching him","note":"Εἰσελθόντι δὲ αὐτῷ — strictly a dative absolute here (him having entered, dative). Matthew uses participial absolute clauses as scene-setting transitions throughout his Gospel. Recognising these constructions reveals Matthew''s narrative architecture"},{"ref":"Acts 2:1","text":"And when the day of Pentecost was fully come, they were all with one accord in one place","note":"Καὶ ἐν τῷ συμπληροῦσθαι τὴν ἡμέραν τῆς πεντηκοστῆς — an articular infinitive construction (in the completing of the day) used where a genitive absolute might appear. Luke''s sophisticated Greek shows the variety of ways Greek sets temporal scenes"}]'
);

-- LESSON 25: THE ARTICLE AS PRONOUN
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  79, 25, 'grammar', 'The Article as Pronoun', 'ὁ δέ, οἱ δέ — Advanced uses of the article — Advanced',
  '{"concept":"The Article as Pronoun","symbol":"ὁ δέ · οἱ δέ","difficulty":"Advanced","overview":"The Greek definite article originally functioned as a demonstrative pronoun (this/that), and this original function survives in the NT, especially in narrative. The construction Article + δέ (= he, she, they — the one/ones just mentioned) is extremely common in the Gospels and Acts for quick subject changes without repeating the noun. Understanding this use helps readers track who is speaking or acting in rapid-dialogue passages.","key_points":["Article + δέ = he/she/they (subject change marker): ὁ δέ = but he; οἱ δέ = but they","Used most commonly in narrative when subject changes from one person to another","The article acts as a pronoun referring back to a recently mentioned person/group","Article + μέν...ὁ δέ = on the one hand...on the other hand (contrast)","The article can also substantivize any word: ὁ ἐρχόμενος = the coming one, the one who comes","Granville Sharp''s Rule: article + noun + καί + noun (no second article) = same person — applies to Titus 2:13 (God and Saviour = one person)"],"examples":[{"greek":"ὁ δὲ ἀποκριθεὶς εἶπεν","translation":"But he, answering, said","reference":"Matthew 4:4","note":"ὁ δέ = Jesus (subject change from the tempter). The article as pronoun rapidly shifts subject back to Jesus without repeating His name"},{"greek":"οἱ δὲ εἶπαν","translation":"But they said","reference":"Luke 24:11","note":"οἱ δέ = the apostles (subject change from the women). The article-as-pronoun tracks the different groups'' reactions in the resurrection narrative"},{"greek":"θεοῦ καὶ σωτῆρος ἡμῶν Ἰησοῦ Χριστοῦ","translation":"of our God and Saviour Jesus Christ","reference":"Titus 2:13","note":"Granville Sharp''s Rule: one article governs both θεοῦ and σωτῆρος — they refer to the same Person: Jesus Christ is God and Saviour"}],"tables":[{"title":"Article + δέ Pronoun Combinations","headers":["Form","Gender/Number","Meaning"],"rows":[["ὁ δέ","Masc singular","But he / And he (subject changed)"],["ἡ δέ","Fem singular","But she / And she"],["τὸ δέ","Neut singular","But it"],["οἱ δέ","Masc plural","But they / And they"],["αἱ δέ","Fem plural","But they (feminine group)"]]},{"title":"Granville Sharp''s Rule (simplified)","headers":["Construction","Meaning","Key Example"],"rows":[["Article + noun1 + καί + noun2 (no article)","Both nouns refer to the SAME person","Titus 2:13: God and Saviour = Jesus"],["Article + noun1 + καί + article + noun2","Two different persons/things","Different referents"]]}],"practice":[{"type":"identify","question":"What does the construction ὁ δέ mean when used as a pronoun in NT narrative?","answer":"But he / and he — it marks a subject change and refers back to the most recently mentioned male person"},{"type":"choice","question":"In Matthew''s Gospel, ὁ δέ... εἶπεν appears frequently. What grammatical function is the article performing?","options":["Identifying a specific noun","Functioning as a pronoun (he) with a subject-change marker (δέ)","Introducing a relative clause","Marking the accusative case"],"answer":1},{"type":"choice","question":"Granville Sharp''s Rule (Titus 2:13: our great God and Saviour Jesus Christ) shows that the one article governing both nouns means they refer to:","options":["Two different persons (God the Father and Jesus)","The same single person — Jesus Christ is identified as both God and Saviour","Three persons of the Trinity","An indefinite reference"],"answer":1}]}',
  '[{"ref":"Titus 2:13","text":"Looking for that blessed hope, and the glorious appearing of the great God and our Saviour Jesus Christ","note":"τοῦ μεγάλου θεοῦ καὶ σωτῆρος ἡμῶν Ἰησοῦ Χριστοῦ — one article governs both θεοῦ and σωτῆρος. Granville Sharp''s Rule: they refer to the same Person. This verse is one of the strongest direct statements of Christ''s deity in the NT"},{"ref":"Luke 24:11","text":"And their words seemed to them as idle tales, and they believed them not","note":"οἱ δέ — but they (the apostles). The article-as-pronoun tracks the subject shift from the women (who reported) to the apostles (who disbelieved). Luke uses this construction skillfully to show the tragic irony of Easter morning"}]'
);

-- LESSON 26: GREEK WORD ORDER AND EMPHASIS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  80, 26, 'grammar', 'Greek Word Order & Emphasis', 'Position drives meaning — Advanced',
  '{"concept":"Greek Word Order and Emphasis","symbol":"πρῶτον · ὑστερον","difficulty":"Advanced","overview":"Unlike English (where word order is relatively fixed and grammatically necessary), Greek word order is relatively free because CASE ENDINGS indicate grammatical function. This freedom means word order in Greek is used primarily for EMPHASIS and RHETORIC rather than grammar. The most emphatic positions in a Greek clause are the BEGINNING (initial emphasis) and the END (final emphasis). The beginning of a sentence is the place of greatest prominence — placing a word first is a deliberate choice.","key_points":["Greek word order is driven by emphasis, not grammar (cases handle function)","First position in a clause = most emphatic (marked, forward-moved element)","Last position can also carry emphasis (anticlimax reversal, climactic placement)","Normal SOV order (Subject-Object-Verb) is the baseline; departures from this are marked","Verbs often come last in Greek, so a verb moved first is very emphatic","Adjectives and genitives moved before their nouns carry forward emphasis","Postpositive words (δέ, γάρ, οὖν) are never first — they claim second position by rule"],"examples":[{"greek":"ἐγώ εἰμι ἡ ἀνάστασις καὶ ἡ ζωή","translation":"I AM the resurrection and the life","reference":"John 11:25","note":"ἐγώ stands first, highly emphatic. The explicit personal pronoun (normally omitted) placed first signals the I AM declaration — divine self-identification before the claim"},{"greek":"τὸν κόσμον ἠγάπησεν ὁ θεός","translation":"The world — God loved it (emphasis on world)","reference":"John 3:16","note":"An alternative word order for John 3:16 where κόσμος is fronted. The actual Greek places οὕτως (so/thus) first — emphasising the manner of God''s love"},{"greek":"ἐν ἀρχῇ ἦν ὁ λόγος","translation":"In the beginning was the Word","reference":"John 1:1","note":"ἐν ἀρχῇ is placed first — the temporal setting is emphatic, deliberately echoing Genesis 1:1. John puts the eternal origin in first position to anchor everything that follows"}],"tables":[{"title":"Emphatic Position Guide","headers":["Position","Emphasis Level","Use in Greek","Example"],"rows":[["First in clause","Highest (marked)","Fronted for prominence","ἐγώ εἰμι — I AM"],["Last in clause","Secondary climax","Saved for impact","...εἶπεν αὐτοῖς ὁ Ἰησοῦς"],["Normal SOV","Neutral/unmarked","Baseline order, no special emphasis","ὁ θεὸς ἀγαπᾷ τὸν κόσμον"]]},{"title":"Rhetorically Significant Word Orders in John 1:1","headers":["Greek phrase","Normal order would be","Actual order signal"],"rows":[["ἐν ἀρχῇ ἦν ὁ λόγος","ὁ λόγος ἦν ἐν ἀρχῇ","ἐν ἀρχῇ fronted — eternity emphasized"],["θεὸς ἦν ὁ λόγος","ὁ λόγος ἦν θεός","θεός fronted — deity of the Word emphasized"]]}],"practice":[{"type":"identify","question":"Why does Greek word order communicate emphasis rather than grammatical function?","answer":"Because Greek case endings already show grammatical function (subject, object, etc.), so word order is free to carry rhetorical emphasis"},{"type":"choice","question":"In John 1:1, θεὸς ἦν ὁ λόγος — the word God (θεός) is placed FIRST in its clause. What does this forward placement communicate?","options":["θεός is the subject","John emphasises the divine nature of the Word by placing θεός first (predicate emphasis — this is what the Word IS)","It is accidental word order","θεός is the object of the verb"],"answer":1},{"type":"choice","question":"In the I AM statements of Jesus (ἐγώ εἰμι), the explicit pronoun ἐγώ is placed first. What does this communicate?","options":["Greek always puts pronouns first","The explicit first-position ἐγώ is maximally emphatic — I and no one else am this thing","ἐγώ is required for the verb εἰμι","It is a first century idiom with no special meaning"],"answer":1}]}',
  '[{"ref":"John 1:1","text":"In the beginning was the Word, and the Word was with God, and the Word was God","note":"Three clauses, each with significant word order choices: ἐν ἀρχῇ fronted (eternity), πρὸς τὸν θεόν (relationship), θεὸς ἦν (deity with θεός fronted). John''s entire prologue is a masterclass in Greek emphasis through word order"},{"ref":"John 11:25","text":"I am the resurrection, and the life: he that believeth in me, though he were dead, yet shall he live","note":"ἐγώ εἰμι — I AM. The explicit ἐγώ fronted before εἰμι is not grammatically required (εἰμι already encodes 1st person) but rhetorically explosive. In the shadow of Lazarus'' tomb, the source of resurrection places Himself in first position"}]'
);

-- LESSON 27: TEXTUAL CRITICISM BASICS
INSERT INTO greek_lessons (id, lesson_number, category, title, subtitle, content, verse_connections) VALUES (
  81, 27, 'grammar', 'Textual Criticism Basics', 'How we got our Greek NT — Advanced',
  '{"concept":"New Testament Textual Criticism","symbol":"𝔓⁴⁵ · א · B","difficulty":"Advanced","overview":"The NT was composed in Greek in the 1st century AD, but we do not have the original manuscripts (autographs). We have approximately 5,800 Greek manuscripts — more than any other ancient document by a massive margin. Textual criticism is the science of comparing these manuscripts to reconstruct the original text. Understanding the basics helps students evaluate why English translations sometimes differ and why study notes say some manuscripts omit or add a reading.","key_points":["5,800+ Greek NT manuscripts (papyri, uncials, minuscules, lectionaries)","No two manuscripts are identical — minor variations exist throughout","Textual variants: most are minor (spelling, word order); very few affect doctrine","Key manuscript families: Alexandrian (oldest, best quality — e.g. Codex Vaticanus B, Sinaiticus א), Byzantine (majority — basis of Textus Receptus/KJV)","Key papyri: 𝔓⁴⁵ (Chester Beatty, ~AD 250), 𝔓⁷⁵ (AD 175-225), 𝔓⁵² (oldest NT fragment, ~AD 125 — John 18)","Principles: prefer shorter reading, harder reading, reading that explains the others, older witnesses"],"examples":[{"greek":"[ὁ δὲ Ἰησοῦς ἔλεγεν, Πάτερ, ἄφες αὐτοῖς, οὐ γὰρ οἴδασιν τί ποιοῦσιν]","translation":"[But Jesus was saying, Father, forgive them; for they do not know what they are doing]","reference":"Luke 23:34","note":"This verse appears in some early manuscripts but is absent from others (Papyrus 75, Codex B). Square brackets in critical editions signal textual uncertainty. Its absence from major Alexandrian texts raises questions; its content perfectly fits Luke''s theology"},{"greek":"[Ἰωάννης δὲ ἐκώλυεν αὐτόν λέγων...]","translation":"[And John was forbidding him saying...]","reference":"Matthew 3:14","note":"Well-attested passage showing John forbidding Jesus — present in all major manuscripts. Contrast with verses in square brackets"},{"greek":"Μαρία ἡ Μαγδαληνή","translation":"Mary Magdalene","reference":"John 20:18","note":"Well-attested personal name showing a stable portion of the text — the vast majority of NT text is not disputed at all"}],"tables":[{"title":"Major Manuscript Witnesses","headers":["Manuscript","Type","Date","Significance"],"rows":[["𝔓⁵²","Papyrus fragment","~AD 125","Oldest NT fragment — John 18:31-33,37-38"],["𝔓⁷⁵","Papyrus codex","~AD 175-225","Luke and John — key Alexandrian witness"],["א (Sinaiticus)","Parchment uncial","~AD 350","Complete NT — found at Sinai by Tischendorf"],["B (Vaticanus)","Parchment uncial","~AD 325-350","Most complete early manuscript — Vatican Library"],["A (Alexandrinus)","Parchment uncial","~AD 400-440","Complete NT + Clement of Rome"],["TR (Textus Receptus)","Printed edition","1516, Erasmus","Basis of KJV NT — primarily Byzantine text"]]},{"title":"Textual Criticism Principles (canons)","headers":["Principle","Meaning","Rationale"],"rows":[["Prefer older witnesses","Earlier = closer to original","Less time for errors to accumulate"],["Prefer harder reading","Scribes simplify, rarely complicate","A difficult reading is less likely to be invented"],["Prefer shorter reading","Scribes add (harmonise), rarely delete","Additions easier to explain than deletions"],["Internal evidence","Does it fit author''s style?","Vocabulary, theology, syntax of the author"]]}],"practice":[{"type":"identify","question":"How many Greek New Testament manuscripts are known to exist?","answer":"Approximately 5,800 — more manuscript evidence than any other ancient document"},{"type":"choice","question":"The oldest surviving NT manuscript fragment is Papyrus 52 (𝔓⁵²), dating to approximately AD 125. Which NT book does it contain?","options":["Matthew","Romans","John","Revelation"],"answer":2},{"type":"choice","question":"The KJV NT was translated from the Textus Receptus (Erasmus, 1516). What manuscript family does the Textus Receptus primarily represent?","options":["Alexandrian (oldest, fewest)","Byzantine (majority, later)","Western (Codex Bezae)","None of the above"],"answer":1}]}',
  '[{"ref":"John 18:31–33","text":"Then said Pilate unto them, Take ye him, and judge him according to your law. The Jews therefore said unto him, It is not lawful for us to put any man to death","note":"This passage is preserved in the oldest NT fragment, 𝔓⁵² (John Rylands Papyrus), dated ~AD 125 — within 30 years of the Gospel''s composition. Holding that fragment, you are 30 years from the apostle John himself. The text we read is historically reliable"},{"ref":"1 John 5:7–8","text":"For there are three that bear record in heaven, the Father, the Word, and the Holy Ghost: and these three are one","note":"The Comma Johanneum — these specific words (Father, Word, Holy Ghost) are absent from all Greek manuscripts before AD 1500, from all early translations, and from all early church fathers. Most modern translations bracket or omit them. Textual criticism protects doctrine by excluding later additions, not undermining it"}]'
);

